async def add_ball_on_surface():
    objs = await get_all_objects()
    # Look for the square object (often named 'box' or 'patch')
    target = next((o for o in objs['objects'] if 'box' in o['name'] or 'patch' in o['name']), None)
    if target:
        pos = target['position']
        return await add_object(name='ball', x=pos[0], y=pos[1], z=pos[2] + 0.04, shape='sphere', color='red', size=0.02)
    # Fallback: if no object found, add at a default location
    return await add_object(name='ball', x=0.5, y=0, z=0.04, shape='sphere', color='red', size=0.02)
